import{_ as s,o as e,c as t,ag as n}from"./chunks/framework.gU7RhlGX.js";const g=JSON.parse('{"title":"Ghostty","description":"","frontmatter":{},"headers":[],"relativePath":"工具/ghossty.md","filePath":"工具/ghossty.md","lastUpdated":1776422487000}'),i={name:"工具/ghossty.md"};function o(l,a,r,h,c,d){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="ghostty" tabindex="-1">Ghostty <a class="header-anchor" href="#ghostty" aria-label="Permalink to &quot;Ghostty&quot;">​</a></h1><blockquote><p><strong>Ghostty</strong> 是由 Mitchell Hashimoto 开发的一个快速、极致原生、且由 GPU 加速的终端终端模拟器。它旨在将高性能渲染与原生操作系统的 UI 体验完美结合。</p></blockquote><h2 id="✨-核心特性" tabindex="-1">✨ 核心特性 <a class="header-anchor" href="#✨-核心特性" aria-label="Permalink to &quot;✨ 核心特性&quot;">​</a></h2><ul><li><strong>极致性能</strong>：利用 GPU 加速（macOS 上使用 Metal，Linux 上使用 OpenGL），即便是在处理海量日志时也能保持丝滑流畅。</li><li><strong>原生体验</strong>：不使用自定义渲染的小部件，而是使用平台原生的 UI 组件来处理窗口、标签页和分屏。</li><li><strong>现代协议支持</strong>：支持 Kitty 图形协议、超链接、同步渲染、连字（Ligatures）等。</li><li><strong>开箱即用</strong>：无需繁琐配置即可获得极佳的默认体验，并内置对 Nerd Fonts 的支持。</li><li><strong>嵌入式核心</strong>：共享核心库 <code>libghostty</code>，确保跨平台逻辑一致且高效。</li></ul><hr><h2 id="📦-安装指南" tabindex="-1">📦 安装指南 <a class="header-anchor" href="#📦-安装指南" aria-label="Permalink to &quot;📦 安装指南&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><p>推荐使用 Homebrew 安装：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ghostty</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者从 <a href="https://ghostty.org" target="_blank" rel="noreferrer">Ghostty 官网</a> 下载 <code>.dmg</code> 文件手动安装。</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>支持通过 Nix、Snap 或从源码编译。</p><ul><li><strong>Nix</strong>: <code>nix-env -iA nixpkgs.ghostty</code></li><li><strong>Snap</strong>: <code>sudo snap install ghostty --edge --classic</code></li></ul><hr><h2 id="⚙️-配置与定义" tabindex="-1">⚙️ 配置与定义 <a class="header-anchor" href="#⚙️-配置与定义" aria-label="Permalink to &quot;⚙️ 配置与定义&quot;">​</a></h2><p>Ghostty 即使没有配置文件也能运行，但你可以通过简单的 <code>key = value</code> 文本文件进行个性化定制。</p><h3 id="配置文件路径" tabindex="-1">配置文件路径 <a class="header-anchor" href="#配置文件路径" aria-label="Permalink to &quot;配置文件路径&quot;">​</a></h3><ul><li><strong>macOS</strong>: <code>~/Library/Application Support/com.mitchellh.ghostty/config</code></li><li><strong>通用</strong>: <code>~/.config/ghostty/config</code></li></ul><h3 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>theme = Monokai Soda</span></span>
<span class="line"><span>font-family = JetBrains Mono</span></span>
<span class="line"><span>font-size = 14</span></span>
<span class="line"><span>window-padding-x = 15</span></span>
<span class="line"><span>window-padding-y = 15</span></span>
<span class="line"><span>cursor-style = block</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="常用快捷键-macos" tabindex="-1">常用快捷键 (macOS) <a class="header-anchor" href="#常用快捷键-macos" aria-label="Permalink to &quot;常用快捷键 (macOS)&quot;">​</a></h3><ul><li><strong>热重载配置</strong>：<code>Cmd + Shift + ,</code> (修改配置文件后无需重启终端)</li><li><strong>显示所有配置说明</strong>：在终端运行 <code>ghostty +show-config --default --docs</code></li></ul><hr><h2 id="🔗-相关资源" tabindex="-1">🔗 相关资源 <a class="header-anchor" href="#🔗-相关资源" aria-label="Permalink to &quot;🔗 相关资源&quot;">​</a></h2><ul><li><a href="https://ghostty.org" target="_blank" rel="noreferrer">官方网站</a></li><li><a href="https://github.com/ghostty-org/ghostty" target="_blank" rel="noreferrer">GitHub 仓库</a></li></ul>`,25)])])}const u=s(i,[["render",o]]);export{g as __pageData,u as default};
